{"file_path": "C:\TASK-99\src\lib\logger.ts", "content": "import winston from "winston";
import { config } from "../config";

const maskSensitive = winston.format((info) => {
  const masked = { ...info };
  // Mask common sensitive fields in log output
  const sensitiveKeys = ["password", "passwordHash", "token", "authorization"];
  for (const key of sensitiveKeys) {
    if (key in masked) {
      (masked as Record<string, unknown>)[key] = "[REDACTED]";
    }
  }
  return masked;
});

export const logger = winston.createLogger({
  level: config.logging.level,
  format: winston.format.combine(
    maskSensitive(),
    winston.format.timestamp(),
    winston.format.errors({ stack: true }),
    config.env === "production"
      ? winston.format.json()
      : winston.format.combine(
          winston.format.colorize(),
          winston.format.printf(
            ({ timestamp, level, message, correlationId, ...meta }) => {
              const cid = correlationId ? ` [${correlationId}]` : "";
              const metaStr =
                Object.keys(meta).length > 0
                  ? ` ${JSON.stringify(meta)}`
                  : "";
              return `${timestamp} ${level}${cid}: ${message}${metaStr}`;
            }
          )
        )
  ),
  transports: [new winston.transports.Console()],
});
"}

