{"file_path": "C:\TASK-99\src\services\auth.service.ts", "content": "import bcrypt from "bcryptjs";
import { prisma } from "../lib/prisma";
import { config } from "../config";
import { AppError } from "../middleware/errorHandler";
import { ErrorCode, AuthenticatedUser } from "../types";
import { signToken } from "../middleware/auth";
import { writeAuditLog } from "./audit.service";

export async function login(params: {
  organizationSlug: string;
  username: string;
  password: string;
  ipAddress?: string;
}): Promise<{ user: AuthenticatedUser; token: string }> {
  const { organizationSlug, username, password, ipAddress } = params;

  // Resolve org
  const org = await prisma.organization.findUnique({
    where: { slug: organizationSlug },
  });
  if (!org || !org.isActive) {
    throw new AppError(401, ErrorCode.UNAUTHORIZED, "Invalid credentials");
  }

  // Find user
  const user = await prisma.user.findUnique({
    where: {
      organizationId_username: {
        organizationId: org.id,
        username,
      },
    },
  });

  // Check lockout before anything else
  const windowStart = new Date(
    Date.now() - config.auth.lockoutWindowMinutes * 60_000
  );
  const recentFailures = await prisma.loginAttempt.count({
    where: {
      username,
      orgSlug: organizationSlug,
      success: false,
      createdAt: { gte: windowStart },
    },
  });
  if (recentFailures >= config.auth.lockoutAttempts) {
    throw new AppError(
      429,
      ErrorCode.ACCOUNT_LOCKED,
      "Account temporarily locked due to too many failed attempts"
    );
  }

  // Validate credentials
  const valid =
    user !== null && (await bcrypt.compare(password, user.passwordHash));

  await prisma.loginAttempt.create({
    data: {
      userId: user?.id,
      username,
      orgSlug: organizationSlug,
      success: valid,
      ipAddress,
    },
  });

  if (!valid) {
    throw new AppError(401, ErrorCode.UNAUTHORIZED, "Invalid credentials");
  }

  if (user!.isBanned) {
    throw new AppError(403, ErrorCode.USER_BANNED, "Account is banned");
  }

  await writeAuditLog({
    organizationId: org.id,
    actorId: user!.id,
    eventType: "user.login",
    ipAddress,
  });

  const principal: AuthenticatedUser = {
    id: user!.id,
    organizationId: org.id,
    username: user!.username,
    role: user!.role,
    isBanned: user!.isBanned,
    muteUntil: user!.muteUntil,
  };

  return { user: principal, token: signToken(principal) };
}

export async function hashPassword(plain: string): Promise<string> {
  return bcrypt.hash(plain, 12);
}
"}

