{"file_path": "C:\TASK-99\src\services\forum.service.ts", "content": "import { ThreadState } from "@prisma/client";
import { prisma } from "../lib/prisma";
import { config } from "../config";
import { AppError } from "../middleware/errorHandler";
import { ErrorCode } from "../types";
import { writeAuditLog } from "./audit.service";

// ─── Threads ──────────────────────────────────────────────────────────────────

const ALLOWED_TRANSITIONS: Record<string, ThreadState[]> = {
  ACTIVE: ["LOCKED", "ARCHIVED"],
  LOCKED: ["ARCHIVED"],
  ARCHIVED: [],
};

export async function createThread(params: {
  organizationId: string;
  sectionId: string;
  subsectionId?: string;
  authorId: string;
  title: string;
  body: string;
  tagIds?: string[];
  isFeatured?: boolean;
}) {
  const { organizationId, authorId, tagIds = [], ...rest } = params;

  return prisma.thread.create({
    data: {
      ...rest,
      organizationId,
      authorId,
      tags: {
        create: tagIds.map((tagId) => ({ tagId })),
      },
    },
    include: { tags: { include: { tag: true } }, author: true },
  });
}

export async function queryThreads(params: {
  organizationId: string;
  sectionId?: string;
  subsectionId?: string;
  state?: ThreadState;
  isPinned?: boolean;
  isFeatured?: boolean;
  tag?: string;
  page: number;
  pageSize: number;
}) {
  const { organizationId, page, pageSize, tag, ...filters } = params;
  const skip = (page - 1) * pageSize;

  const where = {
    organizationId,
    deletedAt: null,
    ...(filters.sectionId && { sectionId: filters.sectionId }),
    ...(filters.subsectionId && { subsectionId: filters.subsectionId }),
    ...(filters.state && { state: filters.state }),
    ...(filters.isPinned !== undefined && { isPinned: filters.isPinned }),
    ...(filters.isFeatured !== undefined && { isFeatured: filters.isFeatured }),
    ...(tag && { tags: { some: { tag: { slug: tag } } } }),
  };

  const [data, total] = await prisma.$transaction([
    prisma.thread.findMany({
      where,
      orderBy: [{ isPinned: "desc" }, { createdAt: "desc" }],
      skip,
      take: pageSize,
      include: { tags: { include: { tag: true } } },
    }),
    prisma.thread.count({ where }),
  ]);

  return { data, total };
}

export async function getThread(id: string, organizationId: string) {
  const thread = await prisma.thread.findFirst({
    where: { id, organizationId, deletedAt: null },
    include: { tags: { include: { tag: true } }, author: true },
  });
  if (!thread) {
    throw new AppError(404, ErrorCode.NOT_FOUND, "Thread not found");
  }
  return thread;
}

export async function transitionThreadState(
  threadId: string,
  organizationId: string,
  toState: ThreadState,
  actorId: string
) {
  const thread = await getThread(threadId, organizationId);

  const allowed = ALLOWED_TRANSITIONS[thread.state] ?? [];
  if (!allowed.includes(toState)) {
    throw new AppError(
      422,
      ErrorCode.INVALID_STATE_TRANSITION,
      `Cannot transition thread from ${thread.state} to ${toState}`
    );
  }

  const updated = await prisma.thread.update({
    where: { id: threadId },
    data: { state: toState },
  });

  await writeAuditLog({
    organizationId,
    actorId,
    eventType: "thread.state_transition",
    resourceType: "Thread",
    resourceId: threadId,
    details: { from: thread.state, to: toState },
  });

  return updated;
}

export async function pinThread(
  threadId: string,
  organizationId: string,
  actorId: string
) {
  const thread = await getThread(threadId, organizationId);

  const pinnedCount = await prisma.thread.count({
    where: {
      organizationId,
      sectionId: thread.sectionId,
      isPinned: true,
      deletedAt: null,
    },
  });

  if (pinnedCount >= config.forum.maxPinnedPerSection) {
    throw new AppError(
      409,
      ErrorCode.PIN_LIMIT_REACHED,
      `Section already has ${config.forum.maxPinnedPerSection} pinned threads`
    );
  }

  const updated = await prisma.thread.update({
    where: { id: threadId },
    data: { isPinned: true },
  });

  await writeAuditLog({
    organizationId,
    actorId,
    eventType: "thread.pinned",
    resourceType: "Thread",
    resourceId: threadId,
  });

  return updated;
}

// ─── Replies ──────────────────────────────────────────────────────────────────

export async function createReply(params: {
  organizationId: string;
  threadId: string;
  authorId: string;
  parentReplyId?: string;
  body: string;
}) {
  const { organizationId, threadId, parentReplyId, ...rest } = params;

  const thread = await getThread(threadId, organizationId);

  if (thread.state === "LOCKED") {
    throw new AppError(
      422,
      ErrorCode.THREAD_LOCKED,
      "Thread is locked and cannot accept new replies"
    );
  }
  if (thread.state === "ARCHIVED") {
    throw new AppError(
      422,
      ErrorCode.THREAD_ARCHIVED,
      "Thread is archived and cannot accept new replies"
    );
  }

  let depth = 1;
  if (parentReplyId) {
    const parent = await prisma.reply.findFirst({
      where: { id: parentReplyId, threadId, deletedAt: null },
    });
    if (!parent) {
      throw new AppError(404, ErrorCode.NOT_FOUND, "Parent reply not found");
    }
    depth = parent.depth + 1;
    if (depth > config.forum.maxReplyDepth) {
      throw new AppError(
        422,
        ErrorCode.REPLY_DEPTH_EXCEEDED,
        `Maximum reply depth of ${config.forum.maxReplyDepth} exceeded`
      );
    }
  }

  return prisma.reply.create({
    data: {
      ...rest,
      organizationId,
      threadId,
      parentReplyId: parentReplyId ?? null,
      depth,
    },
    include: { author: true },
  });
}
"}

