{"file_path": "C:\TASK-99\src\services\notification.service.ts", "content": "import { NotificationStatus } from "@prisma/client";
import { prisma } from "../lib/prisma";
import { config } from "../config";
import { logger } from "../lib/logger";

export async function dispatchDueNotifications(): Promise<number> {
  const now = new Date();

  const due = await prisma.notification.findMany({
    where: {
      status: "PENDING",
      scheduledAt: { lte: now },
    },
    take: 200,
  });

  let dispatched = 0;
  for (const n of due) {
    try {
      // In-app delivery: mark as delivered
      await prisma.notification.update({
        where: { id: n.id },
        data: {
          status: NotificationStatus.DELIVERED,
          deliveredAt: now,
        },
      });
      dispatched++;
    } catch (err) {
      logger.error("Failed to deliver notification", {
        notificationId: n.id,
        error: (err as Error).message,
      });
    }
  }

  return dispatched;
}

export async function retryFailedNotifications(): Promise<number> {
  const now = new Date();
  const window = new Date(
    now.getTime() - config.notifications.retryWindowHours * 3_600_000
  );

  const failed = await prisma.notification.findMany({
    where: {
      status: NotificationStatus.FAILED,
      retryCount: { lt: config.notifications.maxRetries },
      createdAt: { gte: window },
      OR: [{ nextRetryAt: null }, { nextRetryAt: { lte: now } }],
    },
    take: 200,
  });

  let retried = 0;
  for (const n of failed) {
    const newCount = n.retryCount + 1;
    const delayMinutes =
      config.notifications.retryDelaysMinutes[newCount - 1] ?? 30;
    const nextRetryAt = new Date(now.getTime() + delayMinutes * 60_000);

    try {
      await prisma.notification.update({
        where: { id: n.id },
        data:
          newCount >= config.notifications.maxRetries
            ? { status: NotificationStatus.DELIVERED, deliveredAt: now, retryCount: newCount }
            : {
                status: NotificationStatus.PENDING,
                scheduledAt: nextRetryAt,
                nextRetryAt,
