{"file_path": "C:\TASK-99\src\services\risk.service.ts", "content": "import { prisma } from "../lib/prisma";
import { logger } from "../lib/logger";

/**
 * Rule-based risk detection — creates RiskFlag records for moderator review.
 * No automatic punitive actions.
 */
export async function runRiskRules(organizationId: string): Promise<void> {
  const now = new Date();
  const oneHourAgo = new Date(now.getTime() - 3_600_000);
  const thirtyMinAgo = new Date(now.getTime() - 1_800_000);

  await Promise.all([
    checkHighThreadDeletions(organizationId, oneHourAgo),
    checkHighReportVolume(organizationId, thirtyMinAgo),
  ]);
}

async function checkHighThreadDeletions(
  organizationId: string,
  since: Date
): Promise<void> {
  const results = await prisma.auditLog.groupBy({
    by: ["actorId"],
    where: {
      organizationId,
      eventType: "thread.deleted",
      createdAt: { gte: since },
      actorId: { not: null },
    },
    _count: { id: true },
    having: { id: { _count: { gte: 10 } } },
  });

  for (const r of results) {
    if (!r.actorId) continue;
    await upsertFlag(organizationId, r.actorId, "User", "HIGH_THREAD_DELETIONS", {
      count: r._count.id,
      windowStart: since,
    });
  }
}

async function checkHighReportVolume(
  organizationId: string,
  since: Date
): Promise<void> {
  const results = await prisma.auditLog.groupBy({
    by: ["resourceId"],
    where: {
      organizationId,
      eventType: "thread.reported",
      createdAt: { gte: since },
      resourceId: { not: null },
    },
    _count: { id: true },
    having: { id: { _count: { gte: 5 } } },
  });

  for (const r of results) {
    if (!r.resourceId) continue;
    await upsertFlag(organizationId, r.resourceId, "Thread", "HIGH_REPORT_VOLUME", {
      count: r._count.id,
      windowStart: since,
    });
  }
}

async function upsertFlag(
  organizationId: string,
  subjectId: string,
  subjectType: string,
  rule: string,
  details: Record<string, unknown>
): Promise<void> {
  try {
    await prisma.riskFlag.create({
      data: { organizationId, subjectId, subjectType, rule, details },
    });
  } catch (err) {
    logger.warn("Risk flag upsert failed", {
      subjectId,
      rule,
      error: (err as Error).message,
    });
  }
}
"}

