{"file_path": "C:\TASK-99\src\controllers\auth.controller.ts", "content": "import { Request, Response, NextFunction } from "express";
import { z } from "zod";
import { login } from "../services/auth.service";
import { prisma } from "../lib/prisma";
import { AppError } from "../middleware/errorHandler";
import { ErrorCode } from "../types";

const loginSchema = z.object({
  organizationSlug: z.string().min(1),
  username: z.string().min(1),
  password: z.string().min(12, "Password must be at least 12 characters"),
});

export async function handleLogin(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const body = loginSchema.parse(req.body);
    const ipAddress = (req.headers["x-forwarded-for"] as string) ?? req.ip;
    const result = await login({ ...body, ipAddress });
    res.status(200).json(result);
  } catch (err) {
    next(err);
  }
}

export async function handleLogout(
  req: Request,
  res: Response,
  _next: NextFunction
): Promise<void> {
  // Stateless JWT — client discards token; no server-side store in v1
  res.status(200).json({ message: "Logged out" });
}

export async function handleMe(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const user = await prisma.user.findUnique({
      where: { id: req.user!.id },
      select: {
        id: true,
        username: true,
        role: true,
        isBanned: true,
        muteUntil: true,
        organizationId: true,
        createdAt: true,
      },
    });
    if (!user) {
      throw new AppError(404, ErrorCode.NOT_FOUND, "User not found");
    }
    res.status(200).json(user);
  } catch (err) {
    next(err);
  }
}
"}

