{"file_path": "C:\TASK-99\src\controllers\threads.controller.ts", "content": "import { Request, Response, NextFunction } from "express";
import { z } from "zod";
import { ThreadState } from "@prisma/client";
import {
  createThread,
  queryThreads,
  getThread,
  transitionThreadState,
  pinThread,
} from "../services/forum.service";
import { prisma } from "../lib/prisma";
import { AppError } from "../middleware/errorHandler";
import { ErrorCode } from "../types";

const createSchema = z.object({
  sectionId: z.string(),
  subsectionId: z.string().optional(),
  title: z.string().min(1).max(500),
  body: z.string().min(1),
  tagIds: z.array(z.string()).optional(),
  isFeatured: z.boolean().optional(),
});

const stateSchema = z.object({
  toState: z.nativeEnum(ThreadState),
});

export async function handleCreate(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const body = createSchema.parse(req.body);
    const thread = await createThread({
      ...body,
      organizationId: req.user!.organizationId,
      authorId: req.user!.id,
    });
    res.status(201).json(thread);
  } catch (err) {
    next(err);
  }
}

export async function handleList(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const page = Math.max(1, parseInt(req.query.page as string) || 1);
    const pageSize = Math.min(
      100,
      Math.max(1, parseInt(req.query.pageSize as string) || 20)
    );

    const { data, total } = await queryThreads({
      organizationId: req.user!.organizationId,
      sectionId: req.query.sectionId as string | undefined,
      subsectionId: req.query.subsectionId as string | undefined,
      state: req.query.state as ThreadState | undefined,
      isPinned:
        req.query.isPinned !== undefined
          ? req.query.isPinned === "true"
          : undefined,
      isFeatured:
        req.query.isFeatured !== undefined
          ? req.query.isFeatured === "true"
          : undefined,
      tag: req.query.tag as string | undefined,
      page,
      pageSize,
    });

    res.json({
      data,
      pagination: {
        page,
        pageSize,
        total,
        totalPages: Math.ceil(total / pageSize),
      },
    });
  } catch (err) {
    next(err);
  }
}

export async function handleGet(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const thread = await getThread(
      req.params.threadId,
      req.user!.organizationId
    );
    res.json(thread);
  } catch (err) {
    next(err);
  }
}

export async function handleStateTransition(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const { toState } = stateSchema.parse(req.body);
    const thread = await transitionThreadState(
      req.params.threadId,
      req.user!.organizationId,
      toState,
      req.user!.id
    );
    res.json(thread);
  } catch (err) {
    next(err);
  }
}

export async function handlePin(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const thread = await pinThread(
      req.params.threadId,
      req.user!.organizationId,
      req.user!.id
    );
    res.json(thread);
  } catch (err) {
    next(err);
  }
}

export async function handleUnpin(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const existing = await getThread(
      req.params.threadId,
      req.user!.organizationId
    );
    if (!existing.isPinned) {
      throw new AppError(409, ErrorCode.CONFLICT, "Thread is not pinned");
    }
    const thread = await prisma.thread.update({
      where: { id: req.params.threadId },
      data: { isPinned: false },
    });
    res.json(thread);
  } catch (err) {
    next(err);
  }
}
"}

