{"file_path": "C:\TASK-99\src\controllers\replies.controller.ts", "content": "import { Request, Response, NextFunction } from "express";
import { z } from "zod";
import { createReply } from "../services/forum.service";
import { prisma } from "../lib/prisma";
import { AppError } from "../middleware/errorHandler";
import { ErrorCode } from "../types";

const createSchema = z.object({
  parentReplyId: z.string().nullable().optional(),
  body: z.string().min(1),
});

export async function handleCreate(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const user = req.user!;

    if (user.muteUntil && user.muteUntil > new Date()) {
      throw new AppError(
        403,
        ErrorCode.USER_MUTED,
        `You are muted until ${user.muteUntil.toISOString()}`
      );
    }

    const body = createSchema.parse(req.body);
    const reply = await createReply({
      organizationId: user.organizationId,
      threadId: req.params.threadId,
      authorId: user.id,
      parentReplyId: body.parentReplyId ?? undefined,
      body: body.body,
    });
    res.status(201).json(reply);
  } catch (err) {
    next(err);
  }
}

export async function handleList(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const replies = await prisma.reply.findMany({
      where: {
        threadId: req.params.threadId,
        organizationId: req.user!.organizationId,
        deletedAt: null,
      },
      orderBy: { createdAt: "asc" },
      include: { author: { select: { id: true, username: true, role: true } } },
    });
    res.json({ data: replies });
  } catch (err) {
    next(err);
  }
}

export async function handleUpdate(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const { body } = z.object({ body: z.string().min(1) }).parse(req.body);

    const reply = await prisma.reply.findFirst({
      where: {
        id: req.params.replyId,
        organizationId: req.user!.organizationId,
        deletedAt: null,
      },
      include: { thread: true },
    });

    if (!reply) {
      throw new AppError(404, ErrorCode.NOT_FOUND, "Reply not found");
    }
    if (reply.thread.state === "ARCHIVED") {
      throw new AppError(
        422,
