{"file_path": "C:\TASK-99\src\controllers\moderation.controller.ts", "content": "import { Request, Response, NextFunction } from "express";
import { z } from "zod";
import { prisma } from "../lib/prisma";
import { AppError } from "../middleware/errorHandler";
import { ErrorCode } from "../types";
import { writeAuditLog } from "../services/audit.service";
import { config } from "../config";

// ─── Ban / Unban ──────────────────────────────────────────────────────────────

export async function handleBan(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const user = await getOrgUser(req.params.userId, req.user!.organizationId);
    await prisma.user.update({ where: { id: user.id }, data: { isBanned: true } });
    await writeAuditLog({
      organizationId: req.user!.organizationId,
      actorId: req.user!.id,
      eventType: "user.banned",
      resourceType: "User",
      resourceId: user.id,
    });
    res.json({ message: "User banned" });
  } catch (err) {
    next(err);
  }
}

export async function handleUnban(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const user = await getOrgUser(req.params.userId, req.user!.organizationId);
    await prisma.user.update({ where: { id: user.id }, data: { isBanned: false } });
    await writeAuditLog({
      organizationId: req.user!.organizationId,
      actorId: req.user!.id,
      eventType: "user.unbanned",
      resourceType: "User",
      resourceId: user.id,
    });
    res.json({ message: "User unbanned" });
  } catch (err) {
    next(err);
  }
}

// ─── Mute / Unmute ────────────────────────────────────────────────────────────

const muteSchema = z.object({
  durationHours: z
    .number()
    .min(config.forum.muteDurationMinHours)
    .max(config.forum.muteDurationMaxDays * 24),
  reason: z.string().optional(),
});

export async function handleMute(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const { durationHours, reason } = muteSchema.parse(req.body);
    const user = await getOrgUser(req.params.userId, req.user!.organizationId);
    const muteUntil = new Date(Date.now() + durationHours * 3_600_000);
    await prisma.user.update({ where: { id: user.id }, data: { muteUntil } });
    await writeAuditLog({
      organizationId: req.user!.organizationId,
      actorId: req.user!.id,
      eventType: "user.muted",
      resourceType: "User",
      resourceId: user.id,
      details: { durationHours, reason, muteUntil },
    });
    res.json({ muteUntil });
  } catch (err) {
    next(err);
  }
}

export async function handleUnmute(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const user = await getOrgUser(req.params.userId, req.user!.organizationId);
    await prisma.user.update({ where: { id: user.id }, data: { muteUntil: null } });
    await writeAuditLog({
      organizationId: req.user!.organizationId,
      actorId: req.user!.id,
      eventType: "user.unmuted",
      resourceType: "User",
      resourceId: user.id,
    });
    res.json({ message: "User unmuted" });
  } catch (err) {
    next(err);
  }
}

// ─── Bulk Content ─────────────────────────────────────────────────────────────

const bulkSchema = z.object({
  action: z.enum(["archive_threads", "delete_threads", "lock_threads"]),
  threadIds: z.array(z.string()).min(1).max(config.forum.bulkActionMaxItems),
});

export async function handleBulkContent(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const { action, threadIds } = bulkSchema.parse(req.body);
    const orgId = req.user!.organizationId;
    const results: { id: string; status: string }[] = [];

    for (const threadId of threadIds) {
      try {
        if (action === "archive_threads") {
          await prisma.thread.updateMany({
            where: { id: threadId, organizationId: orgId },
            data: { state: "ARCHIVED" },
          });
        } else if (action === "lock_threads") {
          await prisma.thread.updateMany({
            where: { id: threadId, organizationId: orgId, state: "ACTIVE" },
            data: { state: "LOCKED" },
          });
        } else if (action === "delete_threads") {
          await prisma.thread.updateMany({
            where: { id: threadId, organizationId: orgId },
            data: { deletedAt: new Date() },
          });
        }
        await writeAuditLog({
          organizationId: orgId,
          actorId: req.user!.id,
          eventType: `thread.bulk_${action}`,
          resourceType: "Thread",
          resourceId: threadId,
        });
        results.push({ id: threadId, status: "ok" });
      } catch {
        results.push({ id: threadId, status: "failed" });
      }
    }

    res.json({ results });
  } catch (err) {
    next(err);
  }
}

// ─── Recycle Bin ──────────────────────────────────────────────────────────────

export async function handleRecycleBinList(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const items = await prisma.recycleBinItem.findMany({
      where: { expiresAt: { gt: new Date() } },
      include: { thread: true, reply: true },
      orderBy: { deletedAt: "desc" },
    });
    res.json({ data: items });
  } catch (err) {
    next(err);
  }
}

export async function handleRestore(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const item = await prisma.recycleBinItem.findFirst({
      where: { id: req.params.itemId, expiresAt: { gt: new Date() } },
      include: { thread: true, reply: { include: { thread: true } } },
    });
    if (!item) {
      throw new AppError(404, ErrorCode.NOT_FOUND, "Recycle bin item not found or expired");
    }

    if (item.itemType === "THREAD" && item.thread) {
      await prisma.thread.update({
        where: { id: item.thread.id },
        data: { deletedAt: null },
      });
    } else if (item.itemType === "REPLY" && item.reply) {
      await prisma.reply.update({
        where: { id: item.reply.id },
        data: { deletedAt: null },
      });
    }

    await prisma.recycleBinItem.delete({ where: { id: item.id } });
    res.json({ message: "Item restored" });
  } catch (err) {
    next(err);
  }
}

export async function handlePurge(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    await prisma.recycleBinItem.delete({ where: { id: req.params.itemId } });
    res.status(204).send();
  } catch (err) {
    next(err);
  }
}

// ─── Helper ───────────────────────────────────────────────────────────────────

async function getOrgUser(userId: string, organizationId: string) {
  const user = await prisma.user.findFirst({ where: { id: userId, organizationId } });
  if (!user) {
    throw new AppError(404, ErrorCode.NOT_FOUND, "User not found");
  }
  return user;
}
"}

