import { z } from "zod";
import { prisma } from "../lib/prisma";
import {
  dispatchDueNotifications,
  retryFailedNotifications,
} from "../services/notification.service";

export async function handleListNotifications(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const items = await prisma.notification.findMany({
      where: { userId: req.user!.id, organizationId: req.user!.organizationId },
      orderBy: { scheduledAt: "desc" },
      take: 50,
    });
    res.json({ data: items });
  } catch (err) {
    next(err);
  }
}

export async function handleOpenNotification(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    await prisma.notification.updateMany({
      where: {
        id: req.params.notificationId,
        userId: req.user!.id,
      },
      data: { openedAt: new Date(), status: "OPENED" },
    });
    res.json({ message: "Marked as opened" });
  } catch (err) {
    next(err);
  }
}

export async function handleGetSubscriptions(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const subs = await prisma.notificationSubscription.findMany({
      where: { userId: req.user!.id },
    });
    res.json({ data: subs });
  } catch (err) {
    next(err);
  }
}

export async function handleUpdateSubscriptions(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const { subscriptions } = z
      .object({
        subscriptions: z.array(
          z.object({ category: z.string(), isOptIn: z.boolean() })
        ),
      })
      .parse(req.body);

    for (const sub of subscriptions) {
      // Security notices cannot be disabled
      if (sub.category === "security") continue;

      await prisma.notificationSubscription.upsert({
        where: { userId_category: { userId: req.user!.id, category: sub.category } },
        create: { userId: req.user!.id, ...sub },
        update: { isOptIn: sub.isOptIn },
      });
    }

    res.json({ message: "Subscriptions updated" });
  } catch (err) {
    next(err);
  }
}

// Internal endpoints

export async function handleDispatchDue(
  _req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const count = await dispatchDueNotifications();
    res.json({ dispatched: count });
  } catch (err) {
    next(err);
  }
}

export async function handleRetryFailed(
  _req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const count = await retryFailedNotifications();
    res.json({ retried: count });
  } catch (err) {
    next(err);
  }
}
"}

