{"file_path": "C:\TASK-99\src\controllers\analytics.controller.ts", "content": "import { Request, Response, NextFunction } from "express";
import { z } from "zod";
import { prisma } from "../lib/prisma";

const funnelQuerySchema = z.object({
  from: z.string().datetime(),
  to: z.string().datetime(),
});

export async function handleFunnel(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const { from, to } = funnelQuerySchema.parse(req.query);
    const orgId = req.user!.organizationId;
    const start = new Date(from);
    const end = new Date(to);

    const where = {
      organizationId: orgId,
      createdAt: { gte: start, lte: end },
    };

    const [views, registrations, posts, engagements] = await Promise.all([
      prisma.eventLog.count({ where: { ...where, eventType: "thread_view" } }),
      prisma.eventLog.count({ where: { ...where, eventType: "user_registered" } }),
      prisma.eventLog.count({ where: { ...where, eventType: "post_created" } }),
      prisma.eventLog.count({ where: { ...where, eventType: "engagement" } }),
    ]);

    res.json({
      period: { from, to },
      funnel: { view: views, registration: registrations, post: posts, engagement: engagements },
    });
  } catch (err) {
    next(err);
  }
}
"}

