{"file_path": "C:\TASK-99\unit_tests\thread.state.test.ts", "content": "/**
 * Unit tests for thread state transition rules.
 * These tests validate business logic without hitting the database.
 */

const ALLOWED_TRANSITIONS: Record<string, string[]> = {
  ACTIVE: ["LOCKED", "ARCHIVED"],
  LOCKED: ["ARCHIVED"],
  ARCHIVED: [],
};

function canTransition(from: string, to: string): boolean {
  return (ALLOWED_TRANSITIONS[from] ?? []).includes(to);
}

describe("Thread State Transitions", () => {
  test("ACTIVE -> LOCKED is allowed", () => {
    expect(canTransition("ACTIVE", "LOCKED")).toBe(true);
  });

  test("ACTIVE -> ARCHIVED is allowed", () => {
    expect(canTransition("ACTIVE", "ARCHIVED")).toBe(true);
  });

  test("LOCKED -> ARCHIVED is allowed", () => {
    expect(canTransition("LOCKED", "ARCHIVED")).toBe(true);
  });

  test("ARCHIVED -> ACTIVE is not allowed", () => {
    expect(canTransition("ARCHIVED", "ACTIVE")).toBe(false);
  });

  test("ARCHIVED -> LOCKED is not allowed", () => {
    expect(canTransition("ARCHIVED", "LOCKED")).toBe(false);
  });

  test("LOCKED -> ACTIVE is not allowed", () => {
    expect(canTransition("LOCKED", "ACTIVE")).toBe(false);
  });

  test("ACTIVE -> ACTIVE is not a valid transition", () => {
    expect(canTransition("ACTIVE", "ACTIVE")).toBe(false);
  });
});
"}

