{"file_path": "C:\TASK-99\src\controllers\tags.controller.ts", "content": "import { Request, Response, NextFunction } from "express";
import { z } from "zod";
import { prisma } from "../lib/prisma";
import { AppError } from "../middleware/errorHandler";
import { ErrorCode } from "../types";

const tagSchema = z.object({
  name: z.string().min(1).max(100),
  slug: z.string().min(1).max(100).regex(/^[a-z0-9-]+$/, "Slug must be lowercase alphanumeric with hyphens"),
});

export async function handleListTags(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const tags = await prisma.tag.findMany({
      where: { organizationId: req.user!.organizationId, deletedAt: null },
      orderBy: { name: "asc" },
    });
    res.json({ data: tags });
  } catch (err) {
    next(err);
  }
}

export async function handleCreateTag(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const body = tagSchema.parse(req.body);
    const tag = await prisma.tag.create({
      data: { ...body, organizationId: req.user!.organizationId },
    });
    res.status(201).json(tag);
  } catch (err) {
    next(err);
  }
}

export async function handleUpdateTag(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const body = tagSchema.partial().parse(req.body);
    const existing = await prisma.tag.findFirst({
      where: {
        id: req.params.tagId,
        organizationId: req.user!.organizationId,
        deletedAt: null,
      },
    });
    if (!existing) {
      throw new AppError(404, ErrorCode.NOT_FOUND, "Tag not found");
    }
    const tag = await prisma.tag.update({
      where: { id: req.params.tagId },
      data: body,
    });
    res.json(tag);
  } catch (err) {
    next(err);
  }
}

export async function handleDeleteTag(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const existing = await prisma.tag.findFirst({
      where: {
        id: req.params.tagId,
        organizationId: req.user!.organizationId,
        deletedAt: null,
      },
    });
    if (!existing) {
      throw new AppError(404, ErrorCode.NOT_FOUND, "Tag not found");
    }
    await prisma.tag.update({
      where: { id: req.params.tagId },
      data: { deletedAt: new Date() },
    });
    res.status(204).send();
  } catch (err) {
    next(err);
  }
}
"}

