{"file_path": "C:\TASK-99\src\controllers\auth.controller.ts", "content": "import { Request, Response, NextFunction } from "express";
import { loginSchema } from "../schemas/auth.schema";
import { login } from "../services/auth.service";
import { userRepository } from "../repositories/user.repository";
import { AppError } from "../middleware/errorHandler";
import { ErrorCode } from "../types";

export async function handleLogin(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const input = loginSchema.parse(req.body);
    const ipAddress =
      (req.headers["x-forwarded-for"] as string | undefined)?.split(",")[0]?.trim() ??
      req.socket.remoteAddress;

    const result = await login({ ...input, ipAddress });
    res.status(200).json(result);
  } catch (err) {
    next(err);
  }
}

export async function handleLogout(
  _req: Request,
  res: Response,
  _next: NextFunction
): Promise<void> {
  // Stateless JWT — token is discarded client-side.
  // In v2 a token revocation store would live here.
  res.status(200).json({ message: "Logged out successfully" });
}

export async function handleMe(
  req: Request,
  res: Response,
  next: NextFunction
): Promise<void> {
  try {
    const user = await userRepository.findById(req.user!.id);
    if (!user || user.organizationId !== req.user!.organizationId) {
      throw new AppError(404, ErrorCode.NOT_FOUND, "User not found");
    }

    // Never return passwordHash
    const { passwordHash: _pw, ...safe } = user;
    res.status(200).json(safe);
  } catch (err) {
    next(err);
  }
}
"}

