{"file_path": "C:\TASK-99\src\services\analytics.service.ts", "content": "import { prisma } from "../lib/prisma";

export interface FunnelMetrics {
  view: number;
  registration: number;
  post: number;
  engagement: number;
}

export interface EventLogInput {
  organizationId: string;
  userId?: string;
  eventType: string;
  resourceType?: string;
  resourceId?: string;
  metadata?: Record<string, unknown>;
}

export const analyticsService = {
  async getFunnelMetrics(
    organizationId: string,
    from: Date,
    to: Date
  ): Promise<FunnelMetrics> {
    const where = {
      organizationId,
      createdAt: { gte: from, lte: to },
    };

    const [views, registrations, posts, engagements] = await Promise.all([
      prisma.eventLog.count({ where: { ...where, eventType: "thread_view" } }),
      prisma.eventLog.count({ where: { ...where, eventType: "user_registered" } }),
      prisma.eventLog.count({ where: { ...where, eventType: "post_created" } }),
      prisma.eventLog.count({ where: { ...where, eventType: "engagement" } }),
    ]);

    return {
      view: views,
      registration: registrations,
      post: posts,
      engagement: engagements,
    };
  },

  async recordEvent(input: EventLogInput): Promise<void> {
    await prisma.eventLog.create({
      data: {
        organizationId: input.organizationId,
        userId: input.userId,
        eventType: input.eventType,
        resourceType: input.resourceType,
        resourceId: input.resourceId,
        metadata: input.metadata ?? {},
      },
    });
  },
};
"}

