 * Unit tests for thread state transition rules.
 * Tests validate pure business logic without database access.
 */
import { ThreadState } from "@prisma/client";

const ALLOWED_TRANSITIONS: Partial<Record<ThreadState, ThreadState[]>> = {
  [ThreadState.ACTIVE]: [ThreadState.LOCKED, ThreadState.ARCHIVED],
  [ThreadState.LOCKED]: [ThreadState.ARCHIVED],
  [ThreadState.ARCHIVED]: [],
};

function canTransition(from: ThreadState, to: ThreadState): boolean {
  return (ALLOWED_TRANSITIONS[from] ?? []).includes(to);
}

function assertTransitionAllowed(from: ThreadState, to: ThreadState): void {
  if (!canTransition(from, to)) {
    throw new Error(`Cannot transition thread from ${from} to ${to}`);
  }
}

describe("Thread State Transitions", () => {
  describe("Allowed transitions", () => {
    test("ACTIVE → LOCKED", () => {
      expect(canTransition(ThreadState.ACTIVE, ThreadState.LOCKED)).toBe(true);
    });

    test("ACTIVE → ARCHIVED", () => {
      expect(canTransition(ThreadState.ACTIVE, ThreadState.ARCHIVED)).toBe(true);
    });

    test("LOCKED → ARCHIVED", () => {
      expect(canTransition(ThreadState.LOCKED, ThreadState.ARCHIVED)).toBe(true);
    });
  });

  describe("Disallowed transitions", () => {
    test("ARCHIVED → ACTIVE is irreversible", () => {
      expect(canTransition(ThreadState.ARCHIVED, ThreadState.ACTIVE)).toBe(false);
    });

    test("ARCHIVED → LOCKED is irreversible", () => {
      expect(canTransition(ThreadState.ARCHIVED, ThreadState.LOCKED)).toBe(false);
    });

    test("LOCKED → ACTIVE (no rollback)", () => {
      expect(canTransition(ThreadState.LOCKED, ThreadState.ACTIVE)).toBe(false);
    });

    test("ACTIVE → ACTIVE (no self-transition)", () => {
      expect(canTransition(ThreadState.ACTIVE, ThreadState.ACTIVE)).toBe(false);
    });
  });

  describe("assertTransitionAllowed", () => {
    test("does not throw on valid transition", () => {
      expect(() =>
        assertTransitionAllowed(ThreadState.ACTIVE, ThreadState.LOCKED)
      ).not.toThrow();
    });

    test("throws on invalid transition", () => {
      expect(() =>
        assertTransitionAllowed(ThreadState.ARCHIVED, ThreadState.ACTIVE)
      ).toThrow(/Cannot transition/);
    });
  });
});
"}

