58	    const newCount = n.retryCount + 1;
59	    const delayMinutes =
60	      config.notifications.retryDelaysMinutes[newCount - 1] ?? 30;
61	    const nextRetryAt = new Date(now.getTime() + delayMinutes * 60_000);
62	
63	    try {
64	      await prisma.notification.update({
65	        where: { id: n.id },
66	        data:
67	          newCount >= config.notifications.maxRetries
68	            ? { status: NotificationStatus.DELIVERED, deliveredAt: now, retryCount: newCount }
69	            : {
70	                status: NotificationStatus.PENDING,
71	                scheduledAt: nextRetryAt,
72	                nextRetryAt,
73	                retryCount: newCount,
74	              },
75	      });
76	      retried++;
77	    } catch (err) {
78	      logger.error("Retry update failed", {
79	        notificationId: n.id,
80	        error: (err as Error).message,
81	      });
82	    }
83	  }
84	
85	  return retried;
86	}
