88	export async function createNotification(params: {
89	  organizationId: string;
90	  userId: string;
91	  category: string;
92	  title: string;
93	  body: string;
94	  scheduledAt?: Date;
95	}): Promise<void> {
96	  const { scheduledAt = new Date(), ...rest } = params;
97	
98	  // Check subscription (security notices always delivered)
99	  if (rest.category !== "security") {
100	    const sub = await prisma.notificationSubscription.findUnique({
101	      where: { userId_category: { userId: rest.userId, category: rest.category } },
102	    });
103	    if (sub && !sub.isOptIn) return;
104	  }
105	
106	  await prisma.notification.create({
107	    data: { ...rest, scheduledAt },
108	  });
109	}
