6	export async function dispatchDueNotifications(): Promise<number> {
7	  const now = new Date();
8	
9	  const due = await prisma.notification.findMany({
10	    where: {
11	      status: "PENDING",
12	      scheduledAt: { lte: now },
13	    },
14	    take: 200,
15	  });
16	
17	  let dispatched = 0;
18	  for (const n of due) {
19	    try {
20	      // In-app delivery: mark as delivered
21	      await prisma.notification.update({
22	        where: { id: n.id },
23	        data: {
24	          status: NotificationStatus.DELIVERED,
25	          deliveredAt: now,
26	        },
27	      });
28	      dispatched++;
29	    } catch (err) {
30	      logger.error("Failed to deliver notification", {
31	        notificationId: n.id,
32	        error: (err as Error).message,
33	      });
34	    }
35	  }
36	
37	  return dispatched;
38	}
