40	export async function retryFailedNotifications(): Promise<number> {
41	  const now = new Date();
42	  const window = new Date(
43	    now.getTime() - config.notifications.retryWindowHours * 3_600_000
44	  );
45	
46	  const failed = await prisma.notification.findMany({
47	    where: {
48	      status: NotificationStatus.FAILED,
49	      retryCount: { lt: config.notifications.maxRetries },
50	      createdAt: { gte: window },
51	      OR: [{ nextRetryAt: null }, { nextRetryAt: { lte: now } }],
52	    },
53	    take: 200,
54	  });
55	
56	  let retried = 0;
57	  for (const n of failed) {
58	    const newCount = n.retryCount + 1;
59	    const delayMinutes =
60	      config.notifications.retryDelaysMinutes[newCount - 1] ?? 30;
61	    const nextRetryAt = new Date(now.getTime() + delayMinutes * 60_000);
62	
63	    try {
64	      await prisma.notification.update({
65	        where: { id: n.id },
66	        data:
67	          newCount >= config.notifications.maxRetries
68	            ? { status: NotificationStatus.DELIVERED, deliveredAt: now, retryCount: newCount }
69	            : {
70	                status: NotificationStatus.PENDING,
71	                scheduledAt: nextRetryAt,
72	                nextRetryAt,
73	                retryCount: newCount,
74	              },
75	      });
76	      retried++;
77	    } catch (err) {
78	      logger.error("Retry update failed", {
79	        notificationId: n.id,
80	        error: (err as Error).message,
81	      });
82	    }
83	  }
84	
85	  return retried;
86	}
