230	export async function createReply(
231	  organizationId: string,
232	  authorId: string,
233	  threadId: string,
234	  input: CreateReplyInput
235	): Promise<ReplyWithAuthor> {
236	  const thread = await getThread(threadId, organizationId);
237	
238	  if (thread.state === ThreadState.LOCKED) {
239	    throw new AppError(
240	      422,
241	      ErrorCode.THREAD_LOCKED,
242	      "Thread is locked and cannot accept new replies"
243	    );
244	  }
245	  if (thread.state === ThreadState.ARCHIVED) {
246	    throw new AppError(
247	      422,
248	      ErrorCode.THREAD_ARCHIVED,
249	      "Thread is archived and cannot accept new replies"
250	    );
251	  }
252	
253	  let depth = 1;
254	  const parentReplyId = input.parentReplyId ?? undefined;
255	
256	  if (parentReplyId) {
257	    const parent = await replyRepository.findParent(parentReplyId, threadId);
258	    if (!parent) {
259	      throw new AppError(404, ErrorCode.NOT_FOUND, "Parent reply not found");
260	    }
261	    depth = parent.depth + 1;
262	    if (depth > config.forum.maxReplyDepth) {
263	      throw new AppError(
264	        422,
265	        ErrorCode.REPLY_DEPTH_EXCEEDED,
266	        `Reply nesting exceeds the maximum depth of ${config.forum.maxReplyDepth}`
267	      );
268	    }
269	  }
270	
271	  const reply = await replyRepository.create({
272	    organizationId,
273	    threadId,
274	    authorId,
275	    parentReplyId,
276	    depth,
277	    body: input.body,
278	  });
279	
280	  await auditRepository.create({
281	    organizationId,
282	    actorId: authorId,
283	    eventType: "reply.created",
284	    resourceType: "Reply",
285	    resourceId: reply.id,
286	    details: { threadId, depth },
287	  });
288	
289	  return reply;
290	}
