117	
118	export interface BulkActionResult {
119	  id: string;
120	  status: "ok" | "skipped" | "failed";
121	  reason?: string;
122	}
123	
124	export async function bulkContentAction(
125	  organizationId: string,
126	  actorId: string,
127	  input: BulkContentInput
128	): Promise<BulkActionResult[]> {
129	  const results: BulkActionResult[] = [];
130	
131	  for (const threadId of input.threadIds) {
132	    try {
133	      const thread = await threadRepository.findById(threadId, organizationId);
134	      if (!thread) {
135	        results.push({ id: threadId, status: "skipped", reason: "not found" });
136	        continue;
137	      }
138	
139	      if (input.action === "archive_threads") {
140	        if (thread.state === "ARCHIVED") {
141	          results.push({ id: threadId, status: "skipped", reason: "already archived" });
142	          continue;
143	        }
144	        await threadRepository.update(threadId, { state: "ARCHIVED" });
145	      } else if (input.action === "lock_threads") {
146	        if (thread.state !== "ACTIVE") {
147	          results.push({ id: threadId, status: "skipped", reason: `state is ${thread.state}` });
148	          continue;
149	        }
150	        await threadRepository.update(threadId, { state: "LOCKED" });
151	      } else if (input.action === "delete_threads") {
152	        const now = new Date();
153	        const expiresAt = new Date(
154	          now.getTime() + config.forum.recycleBinRetentionDays * 86_400_000
155	        );
156	        await threadRepository.softDelete(threadId, now);
157	        await recycleRepository.create({
158	          itemType: "THREAD",
159	          threadId,
160	          deletedById: actorId,
161	          deletedAt: now,
162	          expiresAt,
163	        });
164	      }
165	
166	      await auditRepository.create({
167	        organizationId,
168	        actorId,
169	        eventType: `thread.bulk_${input.action}`,
170	        resourceType: "Thread",
171	        resourceId: threadId,
172	      });
173	
174	      results.push({ id: threadId, status: "ok" });
175	    } catch (err) {
176	      results.push({
177	        id: threadId,
178	        status: "failed",
179	        reason: (err as Error).message,
180	      });
181	    }
182	  }
183	
184	  return results;
185	}
