195	export async function restoreItem(
196	  itemId: string,
197	  organizationId: string,
198	  actorId: string
199	): Promise<void> {
200	  const item = await recycleRepository.findById(itemId);
201	
202	  if (!item || item.expiresAt < new Date()) {
203	    throw new AppError(
204	      404,
205	      ErrorCode.NOT_FOUND,
206	      "Recycle bin item not found or has expired"
207	    );
208	  }
209	
210	  // Tenant isolation: verify item belongs to caller's org
211	  const itemOrgId =
212	    item.thread?.organizationId ??
213	    item.reply?.thread?.organizationId;
214	
215	  if (itemOrgId !== organizationId) {
216	    throw new AppError(404, ErrorCode.NOT_FOUND, "Recycle bin item not found");
217	  }
218	
219	  if (item.itemType === "THREAD" && item.thread) {
220	    await threadRepository.update(item.thread.id, { deletedAt: null });
221	  } else if (item.itemType === "REPLY" && item.reply) {
222	    // Dependency check: thread must still exist and not be deleted
223	    const parentThread = await threadRepository.findById(
224	      item.reply.threadId,
225	      organizationId
226	    );
227	    if (!parentThread) {
228	      throw new AppError(
229	        409,
230	        ErrorCode.DEPENDENCY_MISSING,
231	        "Cannot restore reply: parent thread no longer exists"
232	      );
233	    }
234	    await prisma.reply.update({
235	      where: { id: item.reply.id },
236	      data: { deletedAt: null },
237	    });
238	  }
239	
240	  await recycleRepository.delete(itemId);
241	
242	  await auditRepository.create({
243	    organizationId,
244	    actorId,
245	    eventType: "recycle_bin.restored",
246	    resourceType: item.itemType,
247	    resourceId: item.thread?.id ?? item.reply?.id,
248	  });
249	}
