11	export async function login(
12	  input: LoginInput & { ipAddress?: string }
13	): Promise<{ user: AuthenticatedUser; token: string }> {
14	  const { organizationSlug, username, password, ipAddress } = input;
15	
16	  // 1. Resolve organization
17	  const org = await organizationRepository.findBySlug(organizationSlug);
18	  if (!org || !org.isActive) {
19	    // Record attempt even when org not found to prevent enumeration timing attacks
20	    await userRepository.createLoginAttempt({
21	      username,
22	      orgSlug: organizationSlug,
23	      success: false,
24	      ipAddress,
25	    });
26	    throw new AppError(401, ErrorCode.UNAUTHORIZED, "Invalid credentials");
27	  }
28	
29	  // 2. Check lockout window before touching user record
30	  const windowStart = new Date(
31	    Date.now() - config.auth.lockoutWindowMinutes * 60_000
32	  );
33	  const recentFailures = await userRepository.countRecentFailedAttempts(
34	    username,
35	    organizationSlug,
36	    windowStart
37	  );
38	  if (recentFailures >= config.auth.lockoutAttempts) {
39	    throw new AppError(
40	      429,
41	      ErrorCode.ACCOUNT_LOCKED,
42	      `Account locked — too many failed attempts. Try again after ${config.auth.lockoutWindowMinutes} minutes.`
43	    );
44	  }
45	
46	  // 3. Find user
47	  const user = await userRepository.findByOrgAndUsername(org.id, username);
48	  const credentialsValid =
49	    user !== null && (await bcrypt.compare(password, user.passwordHash));
50	
51	  // 4. Always record the attempt (before throwing — avoids leaking timing)
52	  await userRepository.createLoginAttempt({
53	    userId: user?.id,
54	    username,
55	    orgSlug: organizationSlug,
56	    success: credentialsValid,
57	    ipAddress,
58	  });
59	
60	  if (!credentialsValid) {
61	    throw new AppError(401, ErrorCode.UNAUTHORIZED, "Invalid credentials");
62	  }
63	
64	  // 5. Ban check after credential verification
65	  if (user!.isBanned) {
66	    throw new AppError(403, ErrorCode.USER_BANNED, "Account is banned");
67	  }
68	
69	  // 6. Audit successful login
70	  await auditRepository.create({
71	    organizationId: org.id,
72	    actorId: user!.id,
73	    eventType: "user.login",
74	    resourceType: "User",
75	    resourceId: user!.id,
76	    ipAddress,
77	  });
78	
79	  const principal: AuthenticatedUser = {
80	    id: user!.id,
81	    organizationId: org.id,
82	    username: user!.username,
83	    role: user!.role,
84	    isBanned: user!.isBanned,
85	    muteUntil: user!.muteUntil,
86	  };
87	
88	  return { user: principal, token: signToken(principal) };
89	}
