22	/**
23	 * Audit log repository — append-only.
24	 * This module deliberately exposes NO update or delete operations.
25	 */
26	export const auditRepository = {
27	  create(data: CreateAuditInput): Promise<AuditLog> {
28	    return prisma.auditLog.create({
29	      data: {
30	        organizationId: data.organizationId,
31	        actorId: data.actorId,
32	        eventType: data.eventType,
33	        resourceType: data.resourceType,
34	        resourceId: data.resourceId,
35	        details: (data.details ?? {}) as Prisma.InputJsonValue,
36	        ipAddress: data.ipAddress,
37	      },
38	    });
39	  },
40	
41	  async query(
42	    input: QueryAuditInput
43	  ): Promise<{ data: AuditLog[]; total: number }> {
44	    const { organizationId, actorId, eventType, page, pageSize } = input;
45	    const skip = (page - 1) * pageSize;
46	
47	    const where: Prisma.AuditLogWhereInput = {
48	      organizationId,
49	      ...(actorId && { actorId }),
50	      ...(eventType && { eventType }),
51	    };
52	
53	    const [data, total] = await prisma.$transaction([
54	      prisma.auditLog.findMany({
55	        where,
56	        orderBy: { createdAt: "desc" },
57	        skip,
58	        take: pageSize,
59	      }),
60	      prisma.auditLog.count({ where }),
61	    ]);
62	
63	    return { data, total };
64	  },
65	};
