31	export async function queryAuditLogs(params: {
32	  organizationId: string;
33	  actorId?: string;
34	  eventType?: string;
35	  page: number;
36	  pageSize: number;
37	}) {
38	  const { organizationId, actorId, eventType, page, pageSize } = params;
39	  const skip = (page - 1) * pageSize;
40	
41	  const where = {
42	    organizationId,
43	    ...(actorId && { actorId }),
44	    ...(eventType && { eventType }),
45	  };
46	
47	  const [data, total] = await prisma.$transaction([
48	    prisma.auditLog.findMany({
49	      where,
50	      orderBy: { createdAt: "desc" },
51	      skip,
52	      take: pageSize,
53	    }),
54	    prisma.auditLog.count({ where }),
55	  ]);
56	
57	  return { data, total };
58	}
