27	  app.use(correlationIdMiddleware);
28	
29	  // ─── HTTP request logging ────────────────────────────────────────────────
30	  app.use(
31	    morgan("combined", {
32	      stream: { write: (msg) => logger.info(msg.trim()) },
33	      skip: (_req, res) => res.statusCode < 400,
34	    })
35	  );
36	
37	  // ─── API routes (versioned at /api/v1) ───────────────────────────────────
38	  app.use("/api/v1", routes);
