24	async function runRiskRulesForAllOrgs(): Promise<void> {
25	  // Evaluate open risk flags older than 7 days and auto-escalate
26	  const threshold = new Date(Date.now() - 7 * 86_400_000);
27	  const stale = await prisma.riskFlag.findMany({
28	    where: { status: "OPEN", createdAt: { lt: threshold } },
29	    select: { id: true, organizationId: true },
30	  });
31	
32	  for (const flag of stale) {
33	    try {
34	      await prisma.riskFlag.update({
35	        where: { id: flag.id },
36	        data: { status: "ESCALATED" },
37	      });
38	      logger.info("Auto-escalated stale risk flag", { flagId: flag.id });
39	    } catch (err) {
40	      logger.error("Risk flag auto-escalation failed", {
41	        flagId: flag.id,
42	        error: (err as Error).message,
43	      });
44	    }
45	  }
46	}
