48	// ─── Scheduler ────────────────────────────────────────────────────────────────
49	
50	export function startScheduler(): void {
51	  if (started) return;
52	  started = true;
53	
54	  // Every minute: dispatch pending notifications whose scheduledAt has passed
55	  cron.schedule("* * * * *", async () => {
56	    try {
57	      await dispatchDueNotifications();
58	    } catch (err) {
59	      logger.error("dispatchDueNotifications job failed", {
60	        error: (err as Error).message,
61	      });
62	    }
63	  });
64	
65	  // Every 5 minutes: retry failed notifications within the 24-hour window
66	  cron.schedule("*/5 * * * *", async () => {
67	    try {
68	      await retryFailedNotifications();
69	    } catch (err) {
70	      logger.error("retryFailedNotifications job failed", {
71	        error: (err as Error).message,
72	      });
73	    }
74	  });
75	
76	  // Every 15 minutes: evaluate risk rules across all active orgs
77	  cron.schedule("*/15 * * * *", async () => {
78	    try {
79	      await runRiskRulesForAllOrgs();
80	    } catch (err) {
81	      logger.error("runRiskRules job failed", {
82	        error: (err as Error).message,
83	      });
84	    }
85	  });
86	
87	  // Daily at 02:00 UTC: purge expired recycle bin items
88	  cron.schedule("0 2 * * *", async () => {
89	    try {
90	      await purgeExpiredRecycleBinItems();
91	    } catch (err) {
92	      logger.error("purgeExpiredRecycleBinItems job failed", {
93	        error: (err as Error).message,
94	      });
95	    }
96	  });
97	
98	  logger.info("Background scheduler started", {
99	    jobs: [
100	      "dispatchNotifications (every 1 min)",
101	      "retryNotifications (every 5 min)",
102	      "riskRules (every 15 min)",
103	      "recycleBinPurge (daily 02:00 UTC)",
104	    ],
105	  });
106	}
