{"file_path": "C:\TASK-99\repo\src\services\risk.service.ts", "content": "import { prisma } from "../lib/prisma";
import { logger } from "../lib/logger";

/**
 * Rule-based risk detection — creates RiskFlag records for moderator review.
 * No automatic punitive actions are taken.
 *
 * Rules:
 *   HIGH_THREAD_DELETIONS  — actor deletes ≥10 threads in 1 hour
 *   HIGH_CANCELLATIONS     — actor performs ≥20 content deletions/undos in 1 hour
 *   HIGH_REPORT_VOLUME     — a thread receives ≥5 reports in 30 minutes
 */
export async function runRiskRules(organizationId: string): Promise<void> {
  const now = new Date();
  const oneHourAgo = new Date(now.getTime() - 3_600_000);
  const thirtyMinAgo = new Date(now.getTime() - 1_800_000);

  await Promise.all([
    checkHighThreadDeletions(organizationId, oneHourAgo),
    checkHighCancellations(organizationId, oneHourAgo),
    checkHighReportVolume(organizationId, thirtyMinAgo),
  ]);
}

// ─── Rule: ≥10 thread deletions in 1 hour ────────────────────────────────────

async function checkHighThreadDeletions(
  organizationId: string,
  since: Date
): Promise<void> {
  const results = await prisma.auditLog.groupBy({
    by: ["actorId"],
    where: {
      organizationId,
      eventType: "thread.deleted",
      createdAt: { gte: since },
      actorId: { not: null },
    },
    _count: { id: true },
    having: { id: { _count: { gte: 10 } } },
  });

  for (const r of results) {
    if (!r.actorId) continue;
    await upsertFlag(
      organizationId,
      r.actorId,
      "User",
      "HIGH_THREAD_DELETIONS",
      { count: r._count.id, windowStart: since.toISOString() }
    );
  }
}

// ─── Rule: ≥20 cancellations/undos in 1 hour ─────────────────────────────────
// Counts reply.deleted + recycle_bin.restored events per actor.
// Thread deletions are a separate, stricter rule above.

async function checkHighCancellations(
  organizationId: string,
  since: Date
): Promise<void> {
  const results = await prisma.auditLog.groupBy({
    by: ["actorId"],
    where: {
      organizationId,
      eventType: { in: ["reply.deleted", "recycle_bin.restored"] },
      createdAt: { gte: since },
      actorId: { not: null },
    },
    _count: { id: true },
    having: { id: { _count: { gte: 20 } } },
  });

  for (const r of results) {
    if (!r.actorId) continue;
    await upsertFlag(
      organizationId,
      r.actorId,
      "User",
      "HIGH_CANCELLATIONS",
      { count: r._count.id, windowStart: since.toISOString() }
    );
  }
}

// ─── Rule: ≥5 reports on a thread in 30 minutes ──────────────────────────────

async function checkHighReportVolume(
  organizationId: string,
  since: Date
): Promise<void> {
  const results = await prisma.auditLog.groupBy({
    by: ["resourceId"],
    where: {
      organizationId,
      eventType: "thread.reported",
      createdAt: { gte: since },
      resourceId: { not: null },
    },
    _count: { id: true },
    having: { id: { _count: { gte: 5 } } },
  });

  for (const r of results) {
    if (!r.resourceId) continue;
    await upsertFlag(
      organizationId,
      r.resourceId,
      "Thread",
      "HIGH_REPORT_VOLUME",
      { count: r._count.id, windowStart: since.toISOString() }
    );
  }
}

// ─── Helpers ──────────────────────────────────────────────────────────────────

async function upsertFlag(
  organizationId: string,
  subjectId: string,
  subjectType: string,
  rule: string,
  details: Record<string, unknown>
): Promise<void> {
  // Avoid creating duplicate OPEN flags for the same subject+rule
  const existing = await prisma.riskFlag.findFirst({
    where: { organizationId, subjectId, rule, status: "OPEN" },
    select: { id: true },
  });

  if (existing) {
    // Update the details on the existing open flag so counts stay current
    await prisma.riskFlag.update({
      where: { id: existing.id },
      data: { details },
    });
    return;
  }

  try {
    await prisma.riskFlag.create({
      data: { organizationId, subjectId, subjectType, rule, details },
    });
    logger.warn("Risk flag created", { organizationId, subjectId, rule });
  } catch (err) {
    logger.error("Risk flag creation failed", {
      subjectId,
      rule,
      error: (err as Error).message,
    });
  }
}
"}

