1	import { Request, Response, NextFunction } from "express";
2	import jwt from "jsonwebtoken";
3	import { Role } from "@prisma/client"; // used in TokenPayload
4	import { config } from "../config";
5	import { AppError } from "./errorHandler";
6	import { ErrorCode, AuthenticatedUser } from "../types";
7	
8	interface TokenPayload {
9	  sub: string;
10	  organizationId: string;
11	  username: string;
12	  role: Role;
13	  isBanned: boolean;
14	  muteUntil: string | null;
15	}
16	
17	export function authenticate(
18	  req: Request,
19	  _res: Response,
20	  next: NextFunction
21	): void {
22	  try {
23	    const header = req.headers.authorization;
24	    if (!header?.startsWith("Bearer ")) {
25	      return next(
26	        new AppError(401, ErrorCode.UNAUTHORIZED, "Bearer token required")
27	      );
28	    }
29	
30	    const token = header.slice(7);
31	    const payload = jwt.verify(token, config.auth.jwtSecret) as TokenPayload;
32	
33	    req.user = {
34	      id: payload.sub,
35	      organizationId: payload.organizationId,
36	      username: payload.username,
37	      role: payload.role,
38	      isBanned: payload.isBanned,
39	      muteUntil: payload.muteUntil ? new Date(payload.muteUntil) : null,
40	    };
41	    next();
42	  } catch {
43	    next(
44	      new AppError(401, ErrorCode.UNAUTHORIZED, "Invalid or expired token")
45	    );
46	  }
47	}
48	
49	export function requireRole(...roles: string[]) {
50	  return (req: Request, _res: Response, next: NextFunction): void => {
51	    if (!req.user) {
52	      throw new AppError(401, ErrorCode.UNAUTHORIZED, "Authentication required");
53	    }
54	    if (!roles.includes(req.user.role as string)) {
55	      throw new AppError(
56	        403,
57	        ErrorCode.FORBIDDEN,
58	        `Required role: ${roles.join(" or ")}`
59	      );
60	    }
61	    next();
62	  };
63	}
64	
65	export function signToken(user: AuthenticatedUser): string {
66	  const payload: TokenPayload = {
67	    sub: user.id,
68	    organizationId: user.organizationId,
69	    username: user.username,
70	    role: user.role,
71	    isBanned: user.isBanned,
72	    muteUntil: user.muteUntil?.toISOString() ?? null,
73	  };
74	  return jwt.sign(payload, config.auth.jwtSecret, {
75	    expiresIn: config.auth.jwtExpiresIn as jwt.SignOptions["expiresIn"],
76	  });
77	}
