2	 * In-memory sliding window rate limiter.
3	 * Single-instance only — no distributed consistency.
4	 */
5	import { Request, Response, NextFunction } from "express";
6	import { config } from "../config";
7	import { AppError } from "./errorHandler";
8	import { ErrorCode } from "../types";
9	
10	interface WindowEntry {
11	  timestamps: number[];
12	}
13	
14	const windows = new Map<string, WindowEntry>();
15	
16	function isAllowed(key: string, limitPerMin: number): boolean {
17	  const now = Date.now();
18	  const windowMs = 60_000;
19	  const cutoff = now - windowMs;
20	
21	  let entry = windows.get(key);
22	  if (!entry) {
23	    entry = { timestamps: [] };
24	    windows.set(key, entry);
25	  }
26	
27	  // Prune old entries
28	  entry.timestamps = entry.timestamps.filter((ts) => ts > cutoff);
29	
30	  if (entry.timestamps.length >= limitPerMin) {
31	    return false;
32	  }
33	
34	  entry.timestamps.push(now);
35	  return true;
36	}
37	
38	// Periodically clean up stale keys to prevent unbounded memory growth
39	setInterval(() => {
40	  const cutoff = Date.now() - 60_000;
41	  for (const [key, entry] of windows.entries()) {
42	    if (entry.timestamps.every((ts) => ts < cutoff)) {
43	      windows.delete(key);
44	    }
45	  }
46	}, 60_000);
