52	): void {
53	  const userId = req.user?.id ?? req.ip ?? "anonymous";
54	  const key = `read:${userId}`;
55	  if (!isAllowed(key, config.rateLimit.readsPerMin)) {
56	    throw new AppError(429, ErrorCode.RATE_LIMITED, "Read rate limit exceeded");
57	  }
