12	export async function login(
13	  input: LoginInput & { ipAddress?: string }
14	): Promise<{ user: AuthenticatedUser; token: string }> {
15	  const { organizationSlug, username, password, ipAddress } = input;
16	
17	  // 1. Resolve organization
18	  const org = await organizationRepository.findBySlug(organizationSlug);
19	  if (!org || !org.isActive) {
20	    // Record attempt even when org not found to prevent enumeration timing attacks
21	    await userRepository.createLoginAttempt({
22	      username,
23	      orgSlug: organizationSlug,
24	      success: false,
25	      ipAddress,
26	    });
27	    throw new AppError(401, ErrorCode.UNAUTHORIZED, "Invalid credentials");
28	  }
29	
30	  // 2. Check lockout window before touching user record
31	  const windowStart = new Date(
32	    Date.now() - config.auth.lockoutWindowMinutes * 60_000
33	  );
34	  const recentFailures = await userRepository.countRecentFailedAttempts(
35	    username,
36	    organizationSlug,
37	    windowStart
38	  );
39	  if (recentFailures >= config.auth.lockoutAttempts) {
40	    throw new AppError(
41	      429,
42	      ErrorCode.ACCOUNT_LOCKED,
43	      `Account locked — too many failed attempts. Try again after ${config.auth.lockoutWindowMinutes} minutes.`
44	    );
45	  }
46	
47	  // 3. Find user
48	  const user = await userRepository.findByOrgAndUsername(org.id, username);
49	  const credentialsValid =
50	    user !== null && (await bcrypt.compare(password, user.passwordHash));
51	
52	  // 4. Always record the attempt (before throwing — avoids leaking timing)
53	  await userRepository.createLoginAttempt({
54	    userId: user?.id,
55	    username,
56	    orgSlug: organizationSlug,
57	    success: credentialsValid,
58	    ipAddress,
59	  });
60	
61	  if (!credentialsValid) {
62	    throw new AppError(401, ErrorCode.UNAUTHORIZED, "Invalid credentials");
63	  }
64	
65	  // 5. Ban check after credential verification
66	  if (user!.isBanned) {
67	    throw new AppError(403, ErrorCode.USER_BANNED, "Account is banned");
68	  }
69	
70	  // 6. Audit successful login
71	  await auditRepository.create({
72	    organizationId: org.id,
73	    actorId: user!.id,
74	    eventType: "user.login",
75	    resourceType: "User",
76	    resourceId: user!.id,
77	    ipAddress,
78	  });
79	
80	  const principal: AuthenticatedUser = {
81	    id: user!.id,
82	    organizationId: org.id,
83	    username: user!.username,
84	    role: user!.role,
85	    isBanned: user!.isBanned,
86	    muteUntil: user!.muteUntil,
87	  };
88	
89	  return { user: principal, token: signToken(principal) };
90	}
