17	export function authenticate(
18	  req: Request,
19	  _res: Response,
20	  next: NextFunction
21	): void {
22	  try {
23	    const header = req.headers.authorization;
24	    if (!header?.startsWith("Bearer ")) {
25	      return next(
26	        new AppError(401, ErrorCode.UNAUTHORIZED, "Bearer token required")
27	      );
28	    }
29	
30	    const token = header.slice(7);
31	    const payload = jwt.verify(token, config.auth.jwtSecret) as TokenPayload;
32	
33	    req.user = {
34	      id: payload.sub,
35	      organizationId: payload.organizationId,
36	      username: payload.username,
37	      role: payload.role,
38	      isBanned: payload.isBanned,
39	      muteUntil: payload.muteUntil ? new Date(payload.muteUntil) : null,
40	    };
41	    next();
42	  } catch {
43	    next(
44	      new AppError(401, ErrorCode.UNAUTHORIZED, "Invalid or expired token")
45	    );
46	  }
47	}
