5	/**
6	 * Rule-based risk detection — creates RiskFlag records for moderator review.
7	 * No automatic punitive actions are taken.
8	 *
9	 * Rules:
10	 *   HIGH_THREAD_DELETIONS  — actor deletes ≥10 threads in 1 hour
11	 *   HIGH_CANCELLATIONS     — actor performs ≥20 content deletions/undos in 1 hour
12	 *   HIGH_REPORT_VOLUME     — a thread receives ≥5 reports in 30 minutes
13	 */
14	export async function runRiskRules(organizationId: string): Promise<void> {
15	  const now = new Date();
16	  const oneHourAgo = new Date(now.getTime() - 3_600_000);
17	  const thirtyMinAgo = new Date(now.getTime() - 1_800_000);
18	
19	  await Promise.all([
20	    checkHighThreadDeletions(organizationId, oneHourAgo),
21	    checkHighCancellations(organizationId, oneHourAgo),
22	    checkHighReportVolume(organizationId, thirtyMinAgo),
23	  ]);
24	}
25	
26	// ─── Rule: ≥10 thread deletions in 1 hour ────────────────────────────────────
27	
28	async function checkHighThreadDeletions(
29	  organizationId: string,
30	  since: Date
31	): Promise<void> {
32	  const results = await prisma.auditLog.groupBy({
33	    by: ["actorId"],
34	    where: {
35	      organizationId,
36	      eventType: "thread.deleted",
37	      createdAt: { gte: since },
38	      actorId: { not: null },
39	    },
40	    _count: { id: true },
41	    having: { id: { _count: { gte: 10 } } },
42	  });
43	
44	  for (const r of results) {
45	    if (!r.actorId) continue;
46	    await upsertFlag(
47	      organizationId,
48	      r.actorId,
49	      "User",
50	      "HIGH_THREAD_DELETIONS",
51	      { count: r._count.id, windowStart: since.toISOString() }
52	    );
53	  }
54	}
55	
56	// ─── Rule: ≥20 cancellations/undos in 1 hour ─────────────────────────────────
57	// Counts reply.deleted + recycle_bin.restored events per actor.
58	// Thread deletions are a separate, stricter rule above.
59	
60	async function checkHighCancellations(
61	  organizationId: string,
62	  since: Date
63	): Promise<void> {
64	  const results = await prisma.auditLog.groupBy({
65	    by: ["actorId"],
66	    where: {
67	      organizationId,
68	      eventType: { in: ["reply.deleted", "recycle_bin.restored"] },
69	      createdAt: { gte: since },
70	      actorId: { not: null },
71	    },
72	    _count: { id: true },
73	    having: { id: { _count: { gte: 20 } } },
74	  });
75	
76	  for (const r of results) {
77	    if (!r.actorId) continue;
78	    await upsertFlag(
79	      organizationId,
80	      r.actorId,
81	      "User",
82	      "HIGH_CANCELLATIONS",
83	      { count: r._count.id, windowStart: since.toISOString() }
84	    );
85	  }
86	}
87	
88	// ─── Rule: ≥5 reports on a thread in 30 minutes ──────────────────────────────
89	
90	async function checkHighReportVolume(
91	  organizationId: string,
92	  since: Date
93	): Promise<void> {
94	  const results = await prisma.auditLog.groupBy({
95	    by: ["resourceId"],
96	    where: {
97	      organizationId,
98	      eventType: "thread.reported",
99	      createdAt: { gte: since },
100	      resourceId: { not: null },
101	    },
102	    _count: { id: true },
103	    having: { id: { _count: { gte: 5 } } },
104	  });
105	
106	  for (const r of results) {
107	    if (!r.resourceId) continue;
108	    await upsertFlag(
109	      organizationId,
110	      r.resourceId,
111	      "Thread",
112	      "HIGH_REPORT_VOLUME",
113	      { count: r._count.id, windowStart: since.toISOString() }
114	    );
115	  }
116	}
117	
118	// ─── Helpers ──────────────────────────────────────────────────────────────────
119	
120	async function upsertFlag(
121	  organizationId: string,
122	  subjectId: string,
123	  subjectType: string,
124	  rule: string,
125	  details: Record<string, unknown>
126	): Promise<void> {
127	  // Avoid creating duplicate OPEN flags for the same subject+rule
128	  const existing = await prisma.riskFlag.findFirst({
129	    where: { organizationId, subjectId, rule, status: "OPEN" },
130	    select: { id: true },
131	  });
132	
133	  if (existing) {
134	    // Update the details on the existing open flag so counts stay current
135	    await prisma.riskFlag.update({
136	      where: { id: existing.id },
137	      data: { details: details as Prisma.InputJsonValue },
138	    });
139	    return;
140	  }
141	
142	  try {
143	    await prisma.riskFlag.create({
144	      data: {
145	        organizationId,
146	        subjectId,
147	        subjectType,
148	        rule,
149	        details: details as Prisma.InputJsonValue,
150	      },
151	    });
152	    logger.warn("Risk flag created", { organizationId, subjectId, rule });
153	  } catch (err) {
154	    logger.error("Risk flag creation failed", {
155	      subjectId,
156	      rule,
157	      error: (err as Error).message,
158	    });
159	  }
160	}
