18	export function notFoundHandler(req: Request, res: Response): void {
19	  const body: ApiErrorResponse = {
20	    error: {
21	      code: ErrorCode.NOT_FOUND,
22	      message: `Route ${req.method} ${req.path} not found`,
23	    },
24	    correlationId: req.correlationId,
25	  };
26	  res.status(404).json(body);
27	}
