29	export function errorHandler(
30	  err: Error,
31	  req: Request,
32	  res: Response,
33	  _next: NextFunction
34	): void {
35	  if (err instanceof AppError) {
36	    const body: ApiErrorResponse = {
37	      error: {
38	        code: err.code,
39	        message: err.message,
40	        details: err.details,
41	      },
42	      correlationId: req.correlationId,
43	    };
44	    res.status(err.statusCode).json(body);
45	    return;
46	  }
47	
48	  if (err instanceof ZodError) {
49	    const body: ApiErrorResponse = {
50	      error: {
51	        code: ErrorCode.VALIDATION_ERROR,
52	        message: "Request validation failed",
53	        details: { issues: err.issues },
54	      },
55	      correlationId: req.correlationId,
56	    };
57	    res.status(400).json(body);
58	    return;
59	  }
60	
61	  logger.error("Unhandled error", {
62	    correlationId: req.correlationId,
63	    error: err.message,
64	    stack: err.stack,
65	  });
66	
